function Notification({ hasUnread, isPremium, errorMessage }) {
  return (
    <div className="sidebar">
      {/* boolean from prop — safe */}
      {hasUnread && <UnreadBadge />}

      {/* boolean from prop — safe */}
      {isPremium && <PremiumBanner />}

      {/* null when no error — safe */}
      {errorMessage && <ErrorBanner message={errorMessage} />}
    </div>
  );
}

// ❌ Bug: renders "0" when cart is empty
function Cart({ items }) {
  return (
    <div>
      {items.length && <ItemList items={items} />}
    </div>
  );
}
// With an empty cart, the DOM shows: <div>0</div>

// ✓ Fix 1: explicit comparison
{items.length > 0 && <ItemList items={items} />}

// ✓ Fix 2: double-bang coercion
{!!items.length && <ItemList items={items} />}

// ✓ Fix 3: ternary for explicit "show nothing"
{items.length > 0 ? <ItemList items={items} /> : null}

// ❌ Risky: '' is falsy — Tag won't render, but intent is unclear
// If label becomes '0' (a valid label), it won't render either
function FileTag({ label }) {
  return (
    <div>
      {label && <Tag text={label} />}
    </div>
  );
}

// ✓ Clear intent: "render only when there is actual content"
{label.length > 0 && <Tag text={label} />}

// ✓ Or use a ternary if an empty label should show a placeholder
{label ? <Tag text={label} /> : <Tag text="Unlabeled" />}

// ❌ Bug: if ratio is NaN, renders "NaN" text in the DOM
function ProgressBar({ completed, total }) {
  const ratio = completed / total; // NaN when total is 0
  return (
    <div>
      {ratio && <Bar percent={ratio * 100} />}
    </div>
  );
}

// ✓ Guard with Number.isFinite
{Number.isFinite(ratio) && ratio > 0 && <Bar percent={ratio * 100} />}

// ✓ Or compute safely with a fallback
const safePct = total > 0 ? (completed / total) * 100 : 0;
{safePct > 0 && <Bar percent={safePct} />}

// Double-bang (!!) converts any value to its boolean equivalent
{!!count && <ItemList />}         // 0 → false, 5 → true
{!!label && <Tag text={label} />} // '' → false, 'hi' → true

// Boolean() constructor — same result, more verbose but explicit
{Boolean(count) && <ItemList />}

// Or move the coercion to a named variable for clarity
const hasItems = items.length > 0;
return hasItems && <ItemList items={items} />;

// All three must be truthy before the element renders
{isLoggedIn && hasPermission && !isLoading && <AdminPanel />}

// When conditions are complex, extract to a named boolean
const canViewAdmin = isLoggedIn && hasPermission && !isLoading;
return canViewAdmin && <AdminPanel />;

// ❌ Pitfall: if totalPages is 0, renders "0" before the element check
{totalPages && currentPage <= totalPages && <Pagination />}
// ✓ Fix
{totalPages > 0 && currentPage <= totalPages && <Pagination />}

// Render the placeholder when there's nothing to show
function Feed({ posts }) {
  return (
    <div>
      {posts.length > 0
        ? <PostList posts={posts} />
        : <EmptyFeed />}
    </div>
  );
}

// || in props — render a fallback value (not element)
function Avatar({ name, src }) {
  return (
    <img
      src={src || '/default-avatar.png'}
      alt={name || 'Anonymous user'}
    />
  );
}

// Nullish coalescing (??) is often better than ||
// ?? only falls back on null/undefined, not 0 or ''
<img src={src ?? '/default-avatar.png'} alt={name ?? 'User'} />

import { Fragment } from 'react';

function UserProfile({ user, isOwner }) {
  return (
    <section>
      <h1>{user.name}</h1>
      <p>{user.bio}</p>

      {/* Short syntax <> </> — no key needed here */}
      {isOwner && (
        <>
          <EditButton userId={user.id} />
          <DeleteButton userId={user.id} />
          <SettingsLink />
        </>
      )}
    </section>
  );
}

// ❌ Both pitfalls: count can be 0, cap can be NaN
function BadBadge({ count, maxDisplay }) {
  const cap = parseInt(maxDisplay); // NaN if maxDisplay is 'auto'
  return (
    <span className="badge">
      {count && (count > cap ? `${cap}+` : count)}
    </span>
  );
}
// When count=0: renders "0"
// When maxDisplay='auto': cap=NaN, count>NaN is false

// ✓ Fixed
function GoodBadge({ count, maxDisplay = 99 }) {
  const cap = typeof maxDisplay === 'number' ? maxDisplay : 99;
  const hasNotifications = count > 0;
  const label = count > cap ? `${cap}+` : String(count);

  return (
    <span className="badge">
      {hasNotifications && label}
    </span>
  );
}

import { render, screen } from '@testing-library/react';

test('renders list when items present', () => {
  render(<Cart items={[{ id: 1, name: 'Widget' }]} />);
  expect(screen.getByRole('list')).toBeInTheDocument();
});

test('renders nothing when cart is empty — not "0"', () => {
  const { container } = render(<Cart items={[]} />);
  // Catches the zero-render bug
  expect(container.textContent).toBe('');
  expect(screen.queryByRole('list')).not.toBeInTheDocument();
});

test('shows badge count when positive', () => {
  render(<NotificationBadge count={5} />);
  expect(screen.getByText('5')).toBeInTheDocument();
});

test('hides badge when count is zero', () => {
  const { container } = render(<NotificationBadge count={0} />);
  expect(container.querySelector('.badge')).not.toBeInTheDocument();
  expect(container.textContent).not.toContain('0');
});

interface Props {
  count: number;     // can be 0
  label?: string;    // can be ''
  data: Item[] | null;
}

function Panel({ count, label, data }: Props) {
  return (
    <div>
      {/* TS allows this — no error, but renders "0" when count is 0 */}
      {count && <Badge>{count}</Badge>}

      {/* TS + react/jsx-no-leaked-render flags this */}
      {label && <Tag>{label}</Tag>}

      {/* Safe: boolean expression, TS is happy */}
      {count > 0 && <Badge>{count}</Badge>}
      {!!label && <Tag>{label}</Tag>}

      {/* null check narrows data — safe because null && ... is null */}
      {data && <DataTable rows={data} />}
    </div>
  );
}

// The live region is always in the DOM — its content changes
function StatusArea({ saveError, saveSuccess }) {
  return (
    <div aria-live="polite" aria-atomic="true">
      {saveError && (
        <p role="alert" className="error">
          Save failed: {saveError}
        </p>
      )}
      {saveSuccess && (
        <p className="success">Changes saved.</p>
      )}
    </div>
  );
}

// aria-live="polite" — announces after user finishes current action
// aria-live="assertive" — interrupts immediately (for critical errors)
// aria-atomic="true" — announces the whole region, not just the change

function DocumentPage({ doc, currentUser }) {
  const canEdit = currentUser.roles.includes('editor');
  const canDelete = currentUser.roles.includes('admin');
  const canComment = currentUser.isVerified && !doc.commentsClosed;

  return (
    <article>
      <h1>{doc.title}</h1>
      <p>{doc.body}</p>

      <div className="actions">
        {canEdit && <EditButton docId={doc.id} />}
        {canDelete && <DeleteButton docId={doc.id} />}
        {canComment && <CommentForm docId={doc.id} />}
      </div>

      {/* Derived booleans make each && safe and readable */}
    </article>
  );
}

function UserList({ isLoading, error, users }) {
  return (
    <section>
      {/* Each state is mutually exclusive — no nested ternary needed */}
      {isLoading && <Spinner />}
      {!isLoading && error && <ErrorMessage message={error} />}
      {!isLoading && !error && users.length === 0 && <EmptyState />}
      {!isLoading && !error && users.length > 0 && (
        <ul>
          {users.map(u => <UserRow key={u.id} user={u} />)}
        </ul>
      )}
    </section>
  );
}

// Alternative: early return pattern avoids chained negations
function UserList({ isLoading, error, users }) {
  if (isLoading) return <Spinner />;
  if (error) return <ErrorMessage message={error} />;
  if (users.length === 0) return <EmptyState />;
  return (
    <ul>
      {users.map(u => <UserRow key={u.id} user={u} />)}
    </ul>
  );
}
